// Generated by Claude Sonnet 4.6

import { helpers } from '@eclipse-che/common';

import { injectKubeConfig, podmanLogin } from '@/services/backend-client/devWorkspaceApi';
import { Workspace } from '@/services/workspace-adapter';

export type RefreshKubeconfigResult = {
  podmanLoginWarning?: string;
};

export async function refreshKubeconfig(workspace: Workspace): Promise<RefreshKubeconfigResult> {
  if (!workspace.isRunning) {
    throw new Error('Workspace must be running to refresh the kubeconfig.');
  }

  await injectKubeConfig(workspace.namespace, workspace.id);

  try {
    await podmanLogin(workspace.namespace, workspace.id);
  } catch (e) {
    return { podmanLoginWarning: helpers.errors.getMessage(e) };
  }

  return {};
}
